INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251202023, 25120202, 2512204, 23, 'MIXED', 'SINGLE', '_________  Art activities can both energize and calm people. READING PASSAGE 3 You should spend about 20 minutes on Questions 27-40, which are based on Reading Passage 3 below. The Long Road to Artificial Intelligence In 1950, the computing pioneer Alan Turing published a paper in the journal Mind entitled ''Computing Machinery and Intelligence''. It was the first serious, scholarly treatment of the concept of Artificial Intelligence (AI). Turing predicted that by the year 2000 the majority of people would be able to speak of machines thinking without expecting to be contradicted, envisaging a world very different from the one he lived in. Despite Turing''s prediction, human-level artificial intelligence had not been achieved by the year 2000. Nevertheless, one significant milestone in artificial intelligence had recently been attained. In 1997 Deep Blue, a computer developed by IBM, defeated the world chess champion Garry Kasparov. Kasparov had beaten previous computer chess programs, which to him seemed predictable and mechanical, but he allegedly said he sensed an ''alien intelligence'' on the other side of the board when he played against Deep Blue. It is instructive to stand back and ponder this moment in the history of AI. The field had accomplished something that half a century beforehand might have been considered its crowning achievement. Humanity had been outstripped by a machine. Of course, a car can move faster than the fastest human sprinter, and a', 'B', '["A","B","C","D","E","F","G","H","I","J","TRUE","FALSE","NOT GIVEN","YES","NO","i","ii","iii","iv","v","vi","vii","viii","ix"]', '["B"]', 'Imported 2025_12_20', 1, 1, 1, 23, 1, 0);
INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251202024, 25120202, 2512205, 24, 'MIXED', 'TEXT', 'Sometimes people want to get involved in art activities but can''t afford it, can''t fit it into their schedule, or don''t have the suitable ___________.', 'attire', NULL, '["attire"]', 'Imported 2025_12_20', 1, 1, 1, 24, 1, 0);
INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251202025, 25120202, 2512205, 25, 'MIXED', 'TEXT', 'A noticeable correlation exists between art involvement ___________ in childhood and those in adulthood.', 'rates', NULL, '["rates"]', 'Imported 2025_12_20', 1, 1, 1, 25, 1, 0);
INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251202026, 25120202, 2512205, 26, 'MIXED', 'TEXT', 'The National Photography Program allows members to grow personally and also gain ___________ for their artistic achievements. crane can carry far more than a champion weight-lifter. But intellectual prowess is what sets human beings apart from the rest of the animals, and chess is a supremely intellectual pursuit. Yet somehow we seemed no nearer to human-level AI than in Turing''s time. How could this be? The problem with Deep Blue was that it was a specialist. All it could do was play chess. Contrast this with a typical human adult. Take the office worker who has just walked past the window of the café where I am sitting with my laptop. Her day has no doubt been a busy patchwork of activities—making a packed lunch, reviewing the children''s homework, driving to work, composing emails, fixing the photocopier, and so on. Each of these activities requires the exercise of multiple sensorimotor skills. Consider the task of making a packed lunch. This involves retrieving utensils and ingredients from various places, opening packets, chopping, cutting, spreading, and so on. In short, a human being is a generalist. A human chess champion can do a whole lot more than just play chess. Moreover, a human being is adaptive. Fixing photocopiers is not an innate capability. It is learned. Had the office worker been born in a different century or a different culture, she would have acquired a different set of skills. And if she has the misfortune to lose her present job, she can re-train for another one. The achievements of AI research in a variety of specialist domains (chess being just one among many success stories) contrast starkly with the field''s failure to produce a machine with general-purpose, adaptive intelligence. So our basic question is, how could we produce artificial general intelligence? An essential feature of biological intelligence is embodiment. Unlike Deep Blue, a human being is an animal with a body, and its brain is part of that body. The brain of an animal has evolved to prevent any harm from coming to that body and to perpetuate the genes that it carries. The body has muscles, enabling it to move, and senses, so that its actions can be made to react to the state of the environment, the better to achieve its goal. The brain shapes the animal''s actions according to what it perceives. Human intelligence, for all its glorious achievements, is fundamentally an extension of animal intelligence, and the human capacities for language, reason, and creativity all rest on a sensorimotor foundation. So while the endeavor to create artificial general intelligence might succeed without much that is essential to biological life, such as metabolism and reproduction, perhaps embodiment is a methodological necessity. Perhaps the need to engage with a messy, dynamic, physical environment full of complex and varied objects, both animate and inanimate, is at the root of intelligence. The only way to form a reliable judgment of the intelligence of an artifact is to observe its behavior in an environment like our own. And the only way to achieve human-level AI, according to this way of thinking, is through robotics. Our basic question can then be reformulated: How can we endow a robot with general intelligence? One possibility is that general intelligence is simply the sum of many specialist Choose the correct letter, A, B, C or D. sensorimotor skills, and up to now, AI hasn''t replicated enough of them. So when robots have been given a certain critical mass of skills, general intelligence will somehow emerge. But even if we gloss over the many engineering questions this proposal begs, it remains unconvincing. The products of such an approach might briefly give the appearance of general intelligence. But nobody would be fooled for very long. The multi-specialist robot is going to get stuck as soon as it has to face a problem that is outside its areas of expertise, an inevitable occurrence in an ever-changing world. Perhaps the capacity to learn is enough to plug the gap here. In an unfamiliar situation, a new skill can be learned. Indeed, learning in its various forms is the backdrop to all intelligence. But learning is time-consuming and risky. The hallmark of general intelligence in a robot is therefore the ability to adapt an existing set of behaviors to new challenges, and to do so without recourse to trial and error or to training by a third party. Only when that can be achieved will artificial intelligence truly match human intelligence.', 'recognition', NULL, '["recognition"]', 'Imported 2025_12_20', 1, 1, 1, 26, 1, 0);
