INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251203018, 25120302, 2512303, 18, 'MIXED', 'SINGLE', 'Paragraph G _________ people''s response times in naming an odour, either when presented with an image that was associated with the odour or one that was not. So, they asked them to sniff vanilla and simultaneously showed them either a picture of ice cream or of cheese, while scanning their brains in a fMRI machine. People named the smells faster when the picture showed something semantically related to them, and when that happened, a structure called the hippocampus was strongly activated. The researchers'' interpretation was that the hippocampus plays a role in integrating information from the senses - information that the brain then uses to decide what it is perceiving. Look at the following findings (Questions 19-24) and the list of researchers Match each finding with the correct researcher, A-D. NB You may use any letter more than once. Choose the correct letter, A, B, C or D. List of Researchers', 'vi', '["A","B","C","D","E","F","G","H","I","J","TRUE","FALSE","NOT GIVEN","YES","NO","i","ii","iii","iv","v","vi","vii","viii","ix"]', '["vi"]', 'Imported 2025_12_26', 1, 1, 1, 18, 1, 0);
