INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251203024, 25120302, 2512304, 24, 'MIXED', 'SINGLE', '_______ The part of brain that governs emotion is more stimulated by smell than an image. READING PASSAGE 3 You should spend about 20 minutes on Questions 27-40, which are based on Reading Passage 3 below. Translating: a key to international understanding? The term ‘translation’ is used for all cases where the meaning of expressions in one language (the ‘source’ language) is turned into the meaning in another (the target language), whether the medium is spoken, written, or signed. In specific professional contexts, however, a distinction is drawn between work with the spoken or signed language (interpreting), and work with the written language (translating), although', 'A', '["A","B","C","D","E","F","G","H","I","J","TRUE","FALSE","NOT GIVEN","YES","NO","i","ii","iii","iv","v","vi","vii","viii","ix"]', '["A"]', 'Imported 2025_12_26', 1, 1, 1, 24, 1, 0);
INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251203025, 25120302, 2512305, 25, 'MIXED', 'SINGLE', 'In the article, what is the opinion about the conventional method of aromatherapy?', 'C', '["A","B","C","D","E","F","G","H","I","J","TRUE","FALSE","NOT GIVEN","YES","NO","i","ii","iii","iv","v","vi","vii","viii","ix"]', '["C"]', 'Imported 2025_12_26', 1, 1, 1, 25, 1, 0);
INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251203026, 25120302, 2512305, 26, 'MIXED', 'SINGLE', 'What is Rachel Hertz''s conclusion? as the part controlling olfaction. or written words. certain tasks blur this distinction. It is sometimes said that there is no task more complex than translation – a claim that can be readily believed when all the variables involved are taken into account. Translators not only need to know their source language well; they must also have a thorough understanding of the field of knowledge covered by the source text, and of any social, cultural, or emotional connotations that need to be specified in the target language if the intended effect is to be conveyed. The same special awareness needs to be present for the target language, so that points of special phrasing, contemporary fashions in expression, local expectations, and so on, can all be taken into account. On the whole, translators work into their mother tongue (or language of habitual use), to ensure a result that sounds as natural as possible – though some translators have argued that, for certain types of text (e.g., scientific material) where translation accuracy is more crucial than naturalness, it makes more sense for the translators to be more fluent in the source language. The aim of translation is to provide semantic equivalence between source and target languages. This is what makes translation different from other linguistic activities, such as adapting, précis writing, and abstracting. However, there are many problems hidden within this apparently simple statement, all to do with what standards of ‘equivalence’ should be expected and accepted. Exact equivalence is of course impossible: no translator could provide a translation that was a perfect parallel to the source text, in such respects as rhythm, puns and cultural allusions. Such a parallel is not even possible when paraphrasing within a single language: there is always some loss of information. On the other hand, there are many kinds of inexact equivalence, any of which can be successful at a certain level of practical functioning. It therefore follows that there is no such thing as a ‘best’ translation. The success of translation depends on the purpose for which it was made, which in turn reflects the needs of the people for whom it was made. A rough-and-ready translation of a letter can suffice to inform a firm of the nature of an enquiry. A translation of a scientific article requires careful attention to meaning, but little attention to stylistic features. The provision of a dubbed film script will warrant scrupulous care over the synchronisation of lip movements, often at the expense of content. Literary work requires a sensitive consideration of form as well as content, and may prompt several translations, each of which emphasises a different aspect of the original. It is easy to see that what might be ‘best’ for one set of circumstances may be entirely unsuitable for another. Several different kinds of translation have been proposed to allow for this range of possibilities. A pragmatic translation emphasises accuracy and knowledge of the subject, as required for instruction manuals and much scientific research. In an aesthetic translation, important for literary material, the focus is on preserving the emotional as well as the cognitive content of the work, and on maintaining some level of stylistic equivalence. Ethnographic or sociolinguistic translations aim to pay full attention to the cultural backgrounds of the authors and the recipients, and take into account differences between source and target languages, and the ways of life in which they are embedded. And there are various kinds of linguistic translation, where the aim is to convey the structural flavour of the original text, often in quite a literal manner, emphasising such features as archaisms, dialectisms, and levels of formality. Most translations, of course, are mixtures of these theoretical types, reflecting the complex reality of language in use. At another level, in a word-for-word translation each word in the source language is translated by a word in the target language. The result often makes no sense, especially when idiomatic constructions are used. In a literal translation, the linguistic structure of the source text is followed, but is normalised according to the rules of the target language. In a free translation, the linguistic structure of the source language is ignored, and an equivalent is found based on the meaning it conveys. Translators aim to produce a text that is as faithful to the original as circumstances require or permit, and yet that reads as if it were written originally in the target language. They aim to be ‘invisible people’ – transferring content without drawing attention to the considerable artistic and technical skills involved in the process. The complexity of the task is apparent, but its importance is often underestimated, and its practitioners’ social status and legal rights undervalued. Some countries view translation as a menial, clerical task, and pay their translators accordingly, while others regard it as a major intellectual discipline in its own right. The question of status is currently much debated, particularly in Europe, where demand for translators is rocketing, especially in relation to the European Union. Reading Passage 3 has eight paragraphs, A-H. Which paragraph contains the following information? Choose the correct letter, A, B, C or D.', 'B', '["A","B","C","D","E","F","G","H","I","J","TRUE","FALSE","NOT GIVEN","YES","NO","i","ii","iii","iv","v","vi","vii","viii","ix"]', '["B"]', 'Imported 2025_12_26', 1, 1, 1, 26, 1, 0);
