INSERT INTO reading_question (id, passage_id, part_group_id, question_number, question_type, answer_mode, question_text, correct_answer, options_json, accepted_answers_json, group_label, case_insensitive, ignore_whitespace, ignore_punctuation, display_order, score, is_deleted) VALUES (251203028, 25120303, 2512306, 28, 'MIXED', 'SINGLE', 'What is the writer''s main idea in the third paragraph? 27  _______  the effect that a client’s requirements have on the nature of a translation 28  _______  contrasting attitudes towards translators 29  _______  a list of the areas of knowledge studied by translators Complete the summary below. Choose NO MORE THAN TWO WORDS from paragraphs C, D and E for each answer. Look at the following features of translating (Questions 34-37) and the types of translation below. Match each feature with the correct type of translation, A-F . A aesthetic B ethnographic C free D literal E pragmatic F word-for-word The goal of translation Translation is an attempt to create a text in the target language which displays 30 _________ with a source text. It is inevitable that not all information can be conveyed, however, so translations are best judged according to their 31 _________; for example, the translator of a business letter or scientific text does not need to consider its 32 _________ aspects, while someone dubbing a film may give a relatively low value to 33 _________. 34  _______   focuses on reproducing the content accurately 35  _______   looks at important cultural aspects of language use 36  _______   follows the original grammatical structures as required by the target language 37  _______   focuses on meaning without necessarily using the original grammatical structures Types of Translation Choose THREE letters, A-F . Which THREE of the following points are mentioned by the writer of the passage?', 'H', '["A","B","C","D","E","F","G","H","I","J","TRUE","FALSE","NOT GIVEN","YES","NO","i","ii","iii","iv","v","vi","vii","viii","ix"]', '["H"